import React, { useState } from "react";

const TaskCard = ({
  id,
  title,
  description,
  priority,
  status,
  date,
  image,
  isVitalPage = false,
  onDelete,
  openEditTask,
}) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  // Форматування класів для стилізації кольорів
  const statusClass = status?.toLowerCase().replace(/\s+/g, "-") || "";
  const priorityClass = priority?.toLowerCase() || "";

  return (
    <div className="task-card-container">
      <div className="task-card-main">
        {/* Header: Status Dot and More Options */}
        <div className="task-card-header">
          <span className={`status-indicator-dot ${statusClass}`}></span>

          <div className="options-wrapper">
            <button
              className="three-dots-trigger"
              onClick={() => setIsMenuOpen(!isMenuOpen)}
            >
              <svg width="16" height="4" viewBox="0 0 16 4" fill="none">
                <circle cx="2" cy="2" r="2" fill="#CBD5E0" />
                <circle cx="8" cy="2" r="2" fill="#CBD5E0" />
                <circle cx="14" cy="2" r="2" fill="#CBD5E0" />
              </svg>
            </button>

            {/* Dropdown Menu from image_69b606.png */}
            {isMenuOpen && (
              <div className="actions-dropdown">
                <div
                  className="action-item"
                  onClick={() => setIsMenuOpen(false)}
                >
                  {isVitalPage ? "Remove from Vital" : "Vital"}
                </div>
                <div
                  className="action-item"
                  onClick={() => {
                    openEditTask(true);
                    setIsMenuOpen(false);
                  }}
                >
                  Edit
                </div>
                <div
                  className="action-item"
                  onClick={() => {
                    onDelete(id);
                    setIsMenuOpen(false);
                  }}
                >
                  Delete
                </div>
                <div
                  className="action-item finish-item"
                  onClick={() => setIsMenuOpen(false)}
                >
                  Finish
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Content Area */}
        <div className="task-card-body">
          <div className="task-text-content">
            <h3 className="task-main-title">{title}</h3>
            <p className="task-main-description">{description}</p>
          </div>

          {image && (
            <div className="task-thumbnail-wrapper">
              <img src={image} alt="task preview" className="task-card-image" />
            </div>
          )}
        </div>

        {/* Footer Meta Data */}
        <div className="task-card-footer">
          <div className="meta-group">
            <span className="meta-label">Priority:</span>
            <span className={`meta-value p-${priorityClass}`}>{priority}</span>
          </div>

          <div className="meta-group">
            <span className="meta-label">Status:</span>
            <span className={`meta-value s-${statusClass}`}>{status}</span>
          </div>

          <div className="meta-date-stamp">Created on: {date}</div>
        </div>
      </div>
    </div>
  );
};

export default TaskCard;
